import React from 'react';
import { Link } from 'react-router-dom';
import { FaFacebookF, FaTwitter, FaInstagram } from 'react-icons/fa';

const Footer = () => {
  return (
    <footer className="bg-blue-800 text-white py-6 mt-10">
      <div className="max-w-7xl mx-auto px-4 grid grid-cols-1 md:grid-cols-3 gap-8 items-center text-center md:text-left">

        {/* Left */}
        <div>
          <h1 className="text-2xl font-bold">MyBlog</h1>
          <p className="text-sm mt-1">&copy; {new Date().getFullYear()} All rights reserved.</p>
        </div>

        {/* Center - Links */}
        <div>
          <h2 className="font-semibold mb-2">Quick Links</h2>
          <ul className="space-y-1">
            <li><Link to="/" className="hover:underline">Home</Link></li>
            <li><Link to="/create" className="hover:underline">Create Blog</Link></li>
            <li><Link to="/category/1" className="hover:underline">Categories</Link></li>
          </ul>
        </div>

        {/* Right - Social */}
        <div>
          <h2 className="font-semibold mb-2">Follow Us</h2>
          <div className="flex justify-center md:justify-start gap-4 text-xl">
            <a href="#" className="hover:text-yellow-300"><FaFacebookF /></a>
            <a href="#" className="hover:text-yellow-300"><FaTwitter /></a>
            <a href="#" className="hover:text-yellow-300"><FaInstagram /></a>
          </div>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
